                Keyboard.Press("{LControlKey down}o{LControlKey up}");
                Delay.Milliseconds(500);

                Report.Log(ReportLevel.Info, "OpenFile",
                    string.Format("[Ctrl+O V2] Cho Select Recipe File dialog ({0}s)...",
